import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const w=JSON.parse('{"title":"📊 市場情緒日報 — 20260501","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_20260501.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_20260501.md"}'),n={name:"Deep32Q知識庫/市場情緒/市場情緒_20260501.md"};function s(i,e,l,c,h,m){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="📊-市場情緒日報-—-20260501" tabindex="-1">📊 市場情緒日報 — 20260501 <a class="header-anchor" href="#📊-市場情緒日報-—-20260501" aria-label="Permalink to &quot;📊 市場情緒日報 — 20260501&quot;">​</a></h1><blockquote><p>掃描時間：2026-05-01 Asia/Taipei 21:15 搜尋工具：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🌍-全球財經頭條-5-條" tabindex="-1">🌍 全球財經頭條（5 條） <a class="header-anchor" href="#🌍-全球財經頭條-5-條" aria-label="Permalink to &quot;🌍 全球財經頭條（5 條）&quot;">​</a></h2><h3 id="_1-🇺🇸-美股-4-30-創歷史新高-s-p-500-收-7-209" tabindex="-1">1. 🇺🇸 美股 4/30 創歷史新高，S&amp;P 500 收 7,209 <a class="header-anchor" href="#_1-🇺🇸-美股-4-30-創歷史新高-s-p-500-收-7-209" aria-label="Permalink to &quot;1. 🇺🇸 美股 4/30 創歷史新高，S&amp;P 500 收 7,209&quot;">​</a></h3><p>S&amp;P 500 飆升 1.0% 至 <strong>7,209.01</strong>（全歷史高點），道瓊 +1.6% 至 49,652.14，納斯達克 +1.0% 至 24,892.31。Alphabet 財報雲端超預期跳漲 10%，Caterpillar 因資料中心建設需求前景 +9.9%，禮來 EPS 超預期 +10%。美股完成五年最佳月度表現。 <em>來源：Saxo Bank — <a href="https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026" target="_blank" rel="noreferrer">https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026</a></em></p><h3 id="_2-🛢️-油價維持高檔-wti-106-布蘭特-111" tabindex="-1">2. 🛢️ 油價維持高檔，WTI $106 / 布蘭特 $111 <a class="header-anchor" href="#_2-🛢️-油價維持高檔-wti-106-布蘭特-111" aria-label="Permalink to &quot;2. 🛢️ 油價維持高檔，WTI $106 / 布蘭特 $111&quot;">​</a></h3><p>荷莫茲海峽持續封閉（第 63 天）推高油價。WTI 約 <strong>$106/桶</strong>，布蘭特約 <strong>$111/桶</strong>。高盛預測布蘭特 2026 年均價將高於 $100。全球原油庫存大量消耗，分析師警告若封鎖持續可能重返 $126+。 <em>來源：Economictimes — <a href="https://economictimes.indiatimes.com/markets/commodities/news/oil-price-today-may-1-crude-oil-holds-above-110/barrel-what-lies-ahead/articleshow/130665530.cms" target="_blank" rel="noreferrer">https://economictimes.indiatimes.com/markets/commodities/news/oil-price-today-may-1-crude-oil-holds-above-110/barrel-what-lies-ahead/articleshow/130665530.cms</a></em></p><h3 id="_3-🏛️-ecb-維持利率-2-00-boe-維持-3-75" tabindex="-1">3. 🏛️ ECB 維持利率 2.00%，BoE 維持 3.75% <a class="header-anchor" href="#_3-🏛️-ecb-維持利率-2-00-boe-維持-3-75" aria-label="Permalink to &quot;3. 🏛️ ECB 維持利率 2.00%，BoE 維持 3.75%&quot;">​</a></h3><p>歐洲央行保留存款利率 <strong>2.00%</strong> 不變，英國央行貨幣政策委員會以 7-1 綴持 3.75%（1 票主張升息 25bp）。兩大央行均考慮 6 月升息以應對中東衝突導致的通膨壓力。聯準會隱含維持全年利率不變，2027 年 10 月前升息機率高於降息。 <em>來源：ECB — <a href="https://www.ecb.europa.eu" target="_blank" rel="noreferrer">https://www.ecb.europa.eu</a>, BoE — <a href="https://www.bankofengland.co.uk" target="_blank" rel="noreferrer">https://www.bankofengland.co.uk</a></em></p><h3 id="_4-📉-全球大宗商品-4-月漲-4-年漲-30" tabindex="-1">4. 📉 全球大宗商品 4 月漲 4%，年漲 30% <a class="header-anchor" href="#_4-📉-全球大宗商品-4-月漲-4-年漲-30" aria-label="Permalink to &quot;4. 📉 全球大宗商品 4 月漲 4%，年漲 30%&quot;">​</a></h3><p>Bloomberg 商品總回報指數 4 月 +4%，YTD +30%。能源領漲（荷莫茲因素），天然氣例外下跌。衝突影響原油、燃料、石化、肥料和部分工業金屬供應鏈。 <em>來源：Saxo Bank — <a href="https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026" target="_blank" rel="noreferrer">https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026</a></em></p><h3 id="_5-🇪🇺-歐洲股市跟漲-stoxx-600-創新高" tabindex="-1">5. 🇪🇺 歐洲股市跟漲，Stoxx 600 創新高 <a class="header-anchor" href="#_5-🇪🇺-歐洲股市跟漲-stoxx-600-創新高" aria-label="Permalink to &quot;5. 🇪🇺 歐洲股市跟漲，Stoxx 600 創新高&quot;">​</a></h3><p>Stoxx 600 +1.4% 至 611.28，德國 DAX +1.4%，FTSE 100 +1.6%。亞洲方面日本日經 +0.7%，澳洲 ASX 200 +0.9%。中國、香港、新加坡勞動節休市。印度 5/4 選舉結果預期波動。 <em>來源：Saxo Bank — <a href="https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026" target="_blank" rel="noreferrer">https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026</a></em></p><hr><h2 id="🇹🇼-台灣財經頭條-5-條" tabindex="-1">🇹🇼 台灣財經頭條（5 條） <a class="header-anchor" href="#🇹🇼-台灣財經頭條-5-條" aria-label="Permalink to &quot;🇹🇼 台灣財經頭條（5 條）&quot;">​</a></h2><h3 id="_1-🏭-台灣-q1-gdp-年增-13-69-近-39-年新高" tabindex="-1">1. 🏭 台灣 Q1 GDP 年增 13.69%，近 39 年新高 <a class="header-anchor" href="#_1-🏭-台灣-q1-gdp-年增-13-69-近-39-年新高" aria-label="Permalink to &quot;1. 🏭 台灣 Q1 GDP 年增 13.69%，近 39 年新高&quot;">​</a></h3><p>主計總處 4/30 公布 Q1 概估 AI 高效運算+雲端基建驅動出口年增 51.10%。民間消費實質成長 4.89%（十季新高）。人均 GDP 預估突破 4 萬美元，超越日本和韓國。 <em>來源：鉅亨網 — <a href="https://m.cnyes.com/news/id/6438047" target="_blank" rel="noreferrer">https://m.cnyes.com/news/id/6438047</a>, UDN — <a href="https://money.udn.com/money/story/5607/9475564" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5607/9475564</a></em></p><h3 id="_2-📊-台股-4-月-7-203-點創歷史最強月線-5-月展望震盪後挑戰-41k" tabindex="-1">2. 📊 台股 4 月 +7,203 點創歷史最強月線，5 月展望震盪後挑戰 41K <a class="header-anchor" href="#_2-📊-台股-4-月-7-203-點創歷史最強月線-5-月展望震盪後挑戰-41k" aria-label="Permalink to &quot;2. 📊 台股 4 月 +7,203 點創歷史最強月線，5 月展望震盪後挑戰 41K&quot;">​</a></h3><p>月線漲幅史上最強，兩度突破 4 萬點，市值躍全球第六。五大利多：Q1 獲利 1.5 兆、戴維斯雙擊、ETF 資金流入、520 行情、Computex。風險：乖離過大、外資 5/1 賣超 536 億、新台幣貶值。 <em>來源：CTEE — <a href="https://www.ctee.com.tw/news/20260501700084-439901" target="_blank" rel="noreferrer">https://www.ctee.com.tw/news/20260501700084-439901</a>, UDN — <a href="https://money.udn.com/money/story/5607/9475564" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5607/9475564</a></em></p><h3 id="_3-💾-台積電-2026-年擴-9-座新廠-清倉-arm-股權套現-75-億" tabindex="-1">3. 💾 台積電 2026 年擴 9 座新廠，清倉 ARM 股權套現 75 億 <a class="header-anchor" href="#_3-💾-台積電-2026-年擴-9-座新廠-清倉-arm-股權套現-75-億" aria-label="Permalink to &quot;3. 💾 台積電 2026 年擴 9 座新廠，清倉 ARM 股權套現 75 億&quot;">​</a></h3><p>台積電加速產能擴張，預計 9 座新建廠和產能轉換。廠務供應商（漢唐、帆宣等）2025 年獲利創新高。台積電全數出清 ARM 股權，套現約 75 億元，支持擴廠現金流。 <em>來源：CNA — <a href="https://www.cna.com.tw/news/afe/202605010022.aspx" target="_blank" rel="noreferrer">https://www.cna.com.tw/news/afe/202605010022.aspx</a>, UDN — <a href="https://udn.com/news/story/7240/9475748" target="_blank" rel="noreferrer">https://udn.com/news/story/7240/9475748</a></em></p><h3 id="_4-⚡-四大雲端巨頭-2026-年-ai-基建支出合計-7-250-億美元" tabindex="-1">4. ⚡ 四大雲端巨頭 2026 年 AI 基建支出合計 7,250 億美元 <a class="header-anchor" href="#_4-⚡-四大雲端巨頭-2026-年-ai-基建支出合計-7-250-億美元" aria-label="Permalink to &quot;4. ⚡ 四大雲端巨頭 2026 年 AI 基建支出合計 7,250 億美元&quot;">​</a></h3><p>Google、微軟、Meta、亞馬遜 AI 投資進入超級循環。台灣供應鏈（半導體、散熱、高速傳輸、PCB）全面受惠。市場資金從 GPU 算力轉向 ASIC 客製化晶片（世芯-KY、聯發科）。 <em>來源：LTN — <a href="https://ec.ltn.com.tw/article/breakingnews/5422287" target="_blank" rel="noreferrer">https://ec.ltn.com.tw/article/breakingnews/5422287</a>, CTEE — <a href="https://www.ctee.com.tw/news/20260501700074-439901" target="_blank" rel="noreferrer">https://www.ctee.com.tw/news/20260501700074-439901</a></em></p><h3 id="_5-⚠️-openai-營收不如預期-可能影響台灣供應鏈訂單" tabindex="-1">5. ⚠️ OpenAI 營收不如預期，可能影響台灣供應鏈訂單 <a class="header-anchor" href="#_5-⚠️-openai-營收不如預期-可能影響台灣供應鏈訂單" aria-label="Permalink to &quot;5. ⚠️ OpenAI 營收不如預期，可能影響台灣供應鏈訂單&quot;">​</a></h3><p>OpenAI 營收成長不如預期，可能導致 AI 資料中心採購合約生變，影響廣達（2382）、緯創（3231）等伺服器供應商後續訂單。英特爾 EMIB 先進封裝良率達 90%，將應用於 Google 和 NVIDIA 下一代晶片，威脅台積電 CoWoS。 <em>來源：TechNews — <a href="https://finance.technews.tw/2026/05/01/openai-10-billion-compute-procurement-at-risk-impacting-quanta-wistron-orders/" target="_blank" rel="noreferrer">https://finance.technews.tw/2026/05/01/openai-10-billion-compute-procurement-at-risk-impacting-quanta-wistron-orders/</a>, NextApple — <a href="https://news.nextapple.com/finance/20260501/8C0B78679B6AAEA7DF3E7C0A4B31EF26" target="_blank" rel="noreferrer">https://news.nextapple.com/finance/20260501/8C0B78679B6AAEA7DF3E7C0A4B31EF26</a></em></p><hr><h2 id="📊-市場情緒判斷" tabindex="-1">📊 市場情緒判斷 <a class="header-anchor" href="#📊-市場情緒判斷" aria-label="Permalink to &quot;📊 市場情緒判斷&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">判斷</th><th style="text-align:left;">理由</th></tr></thead><tbody><tr><td style="text-align:center;">🟡 <strong>中性偏多</strong></td><td style="text-align:left;">美股創高、台股 5 月展望正面、AI 基建超級循環；但荷莫茲油價壓力、全球通膨、ECB/BoE 升息預期構成逆風。短期波動加大，中長期多頭結構未破壞。</td></tr></tbody></table><hr><h2 id="📚-資料來源-全" tabindex="-1">📚 資料來源（全） <a class="header-anchor" href="#📚-資料來源-全" aria-label="Permalink to &quot;📚 資料來源（全）&quot;">​</a></h2><ol><li>Saxo Bank Market Quick Take May 1: <a href="https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026" target="_blank" rel="noreferrer">https://www.home.saxo/content/articles/macro/market-quick-take---1-may-2026-01052026</a></li><li>Economictimes Oil Price May 1: <a href="https://economictimes.indiatimes.com/markets/commodities/news/oil-price-today-may-1-crude-oil-holds-above-110/barrel-what-lies-ahead/articleshow/130665530.cms" target="_blank" rel="noreferrer">https://economictimes.indiatimes.com/markets/commodities/news/oil-price-today-may-1-crude-oil-holds-above-110/barrel-what-lies-ahead/articleshow/130665530.cms</a></li><li>ECB Interest Rate: <a href="https://www.ecb.europa.eu" target="_blank" rel="noreferrer">https://www.ecb.europa.eu</a></li><li>BoE Interest Rate: <a href="https://www.bankofengland.co.uk" target="_blank" rel="noreferrer">https://www.bankofengland.co.uk</a></li><li>CNA 台積電擴廠: <a href="https://www.cna.com.tw/news/afe/202605010022.aspx" target="_blank" rel="noreferrer">https://www.cna.com.tw/news/afe/202605010022.aspx</a></li><li>UDN 台積電 ARM: <a href="https://udn.com/news/story/7240/9475748" target="_blank" rel="noreferrer">https://udn.com/news/story/7240/9475748</a></li><li>CTEE 台股展望: <a href="https://www.ctee.com.tw/news/20260501700084-439901" target="_blank" rel="noreferrer">https://www.ctee.com.tw/news/20260501700084-439901</a></li><li>UDN 台灣經濟: <a href="https://money.udn.com/money/story/5607/9475564" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5607/9475564</a></li><li>LTN AI 基建: <a href="https://ec.ltn.com.tw/article/breakingnews/5422287" target="_blank" rel="noreferrer">https://ec.ltn.com.tw/article/breakingnews/5422287</a></li><li>TechNews OpenAI: <a href="https://finance.technews.tw/2026/05/01/openai-10-billion-compute-procurement-at-risk-impacting-quanta-wistron-orders/" target="_blank" rel="noreferrer">https://finance.technews.tw/2026/05/01/openai-10-billion-compute-procurement-at-risk-impacting-quanta-wistron-orders/</a></li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 抓取時間：2026-05-01 Asia/Taipei 21:15</em></p>',34)])])}const d=a(n,[["render",s]]);export{w as __pageData,d as default};
